import i18n, { useTranslation } from './i18n-sdk';
import { useCallback } from 'react';
export interface serverI18nProps {
    i18nKey: string;
    defaultValue: string;
    params?: object;
}
export function useSptTranslation() {
    const { t, i18n } = useTranslation();
    return {
        i18n,
        t: useCallback(
            (key, options = {}) => {
                if(!key) return ''
                if (typeof key === 'string') {
                    return t(key, options);
                }
                if (typeof key === 'object') {
                    let i18Vo = key as serverI18nProps;
                    return t(i18Vo.i18nKey, {
                        ...i18Vo.params,
                        ...options,
                        // 接options
                        defaultValue: options.defaultValue?options.defaultValue:i18Vo.defaultValue,
                    });
                }
                return '国际化格式错误，请检查!';
            },
            [t]
        )
    };
}
export const sptI18n = (key: string | serverI18nProps, options: any = {}) => {
    if(!key) return ''
    if (typeof key === 'string') {
        return i18n.t(key, options);
    }
    if (typeof key === 'object') {
        let i18Vo = key as serverI18nProps;
        return i18n.t(i18Vo.i18nKey, { defaultValue: i18Vo.defaultValue, ...i18Vo.params });
    }
    return '国际化格式错误，请检查!';
};
